import{_ as d,o as e,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Настройки страниц","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/Page/page-settings.md","filePath":"ru-RU/Page/page-settings.md","lastUpdated":1781962217000}'),o={name:"ru-RU/Page/page-settings.md"};function n(i,t,l,s,c,g){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="настроики-страниц" tabindex="-1">Настройки страниц <a class="header-anchor" href="#настроики-страниц" aria-label="Permalink to &quot;Настройки страниц&quot;">​</a></h1><p>Page settings управляют отображением сайта, настройками страницы загрузки по умолчанию, фоновыми изображениями и видом админ-панели.</p><h2 id="global-settings" tabindex="-1">Global Settings <a class="header-anchor" href="#global-settings" aria-label="Permalink to &quot;Global Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Опция</th><th>Назначение</th></tr></thead><tbody><tr><td>Site title</td><td>Заголовок, который показывается во вкладке браузера.</td></tr><tr><td>Site icon</td><td>Маленькая иконка во вкладке браузера.</td></tr><tr><td>ImgBed name</td><td>Название, которое показывается на frontend pages.</td></tr><tr><td>ImgBed logo</td><td>Изображение логотипа на frontend pages.</td></tr><tr><td>Logo link</td><td>URL, который открывается при нажатии на логотип или avatar.</td></tr><tr><td>Background switch interval</td><td>Интервал ротации нескольких фонов в миллисекундах. <code>60000</code> означает 60 секунд.</td></tr><tr><td>Background opacity</td><td>Прозрачность фонового изображения от <code>0</code> до <code>1</code>. Меньшие значения делают фон светлее.</td></tr><tr><td>Default URL prefix</td><td>Prefix для генерации ссылок на изображения. Пустое поле означает, что используется текущий домен сайта.</td></tr></tbody></table><h2 id="client-settings" tabindex="-1">Client Settings <a class="header-anchor" href="#client-settings" aria-label="Permalink to &quot;Client Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Опция</th><th>Назначение</th></tr></thead><tbody><tr><td>Announcement</td><td>Объявление вверху страницы загрузки. Поддерживается HTML.</td></tr><tr><td>Default upload channel</td><td>Upload channel, выбранный на странице загрузки по умолчанию. Также можно выбрать Smart Dispatch.</td></tr><tr><td>Default upload directory</td><td>Директория загрузки по умолчанию, например <code>/user/</code>. Пусто или <code>/</code> означает root.</td></tr><tr><td>Default naming method</td><td>Стратегия генерации filename после upload по умолчанию. См. ниже.</td></tr><tr><td>Convert to WebP by default</td><td>Преобразует изображения в WebP перед upload.</td></tr><tr><td>Enable compression by default</td><td>Сжимает изображения локально в браузере перед upload.</td></tr><tr><td>Default compression threshold</td><td>Автоматически сжимает, когда изображение превышает этот размер в MB.</td></tr><tr><td>Default target size</td><td>Целевой размер файла после сжатия, в MB.</td></tr><tr><td>Login page background</td><td>Фоновое изображение страницы входа пользователя.</td></tr><tr><td>Upload page background</td><td>Фоновое изображение страницы загрузки.</td></tr><tr><td>Footer portal link</td><td>URL, который открывает footer portal button.</td></tr><tr><td>Hide footer</td><td>Скрывает frontend footer, когда включено.</td></tr></tbody></table><h2 id="admin-settings" tabindex="-1">Admin Settings <a class="header-anchor" href="#admin-settings" aria-label="Permalink to &quot;Admin Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Опция</th><th>Назначение</th></tr></thead><tbody><tr><td>Admin login background</td><td>Фоновое изображение страницы входа администратора.</td></tr><tr><td>Admin background</td><td>Фоновое изображение admin pages. Можно указать один image URL или несколько URL.</td></tr><tr><td>Image loading mode</td><td>Режим загрузки preview для admin file list. Original загружает оригинальные изображения. Smart loading предпочитает thumbnails для публичных изображений и originals для restricted images.</td></tr><tr><td>Thumbnail source</td><td>Сервис генерации thumbnails: wsrv.nl, Cloudflare Image Resizing или WordPress Photon. Cloudflare Image Resizing нужно включить в Cloudflare перед выбором.</td></tr><tr><td>Live2D widget</td><td>Показывает Live2D-персонажа в админ-панели.</td></tr><tr><td>Firework click effect</td><td>Показывает эффект фейерверка при нажатии на страницу.</td></tr><tr><td>Star cursor trail</td><td>Показывает звездный след при движении мыши.</td></tr></tbody></table><h2 id="форматы-фоновых-изображении" tabindex="-1">Форматы фоновых изображений <a class="header-anchor" href="#форматы-фоновых-изображении" aria-label="Permalink to &quot;Форматы фоновых изображений&quot;">​</a></h2><p>Login page background, upload page background и admin login background поддерживают:</p><table tabindex="0"><thead><tr><th>Значение</th><th>Эффект</th></tr></thead><tbody><tr><td><code>bing</code></td><td>Использует ротацию обоев Bing.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>Ротирует несколько изображений.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>Использует одно фоновое изображение.</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>Использует random image API link. Можно настроить свой Random Image API в Other Settings, затем вставить сгенерированную random image link как single-background entry.</td></tr></tbody></table><p>Admin background поддерживает image URLs. Несколько URL можно разделять английскими запятыми, как подсказано на странице. Пустое поле означает default background.</p><h2 id="default-naming-method" tabindex="-1">Default Naming Method <a class="header-anchor" href="#default-naming-method" aria-label="Permalink to &quot;Default Naming Method&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Result</th></tr></thead><tbody><tr><td>Default</td><td>Time-random prefix + original filename, например <code>1760000000000_cat.png</code>.</td></tr><tr><td>Prefix only</td><td>Только time-random prefix и extension, например <code>1760000000000.png</code>.</td></tr><tr><td>Original name only</td><td>Сохраняет original filename, например <code>cat.png</code>. Если есть дубль, ImgBed добавляет <code>(1)</code>, <code>(2)</code> и так далее.</td></tr><tr><td>Short link</td><td>Использует 8-символьный short ID и extension, например <code>a1b2c3d4.png</code>.</td></tr></tbody></table>',14)])])}const u=d(o,[["render",n]]);export{m as __pageData,u as default};
